import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import './Courses.css';

const Courses = () => {
  const [activeTab, setActiveTab] = useState('all');
  const [menuOpen, setMenuOpen] = useState(false);

  const courses = [
    {
      id: 1,
      title: 'Wildlife Conservation Basics',
      description: 'Learn the fundamentals of wildlife conservation and protection.',
      image: '/conservation.jpg',
      duration: '4 weeks',
      level: 'Beginner',
      progress: 0
    },
    {
      id: 2,
      title: 'Technology in Conservation',
      description: 'Explore how modern technology is revolutionizing wildlife protection.',
      image: '/technology.jpg',
      duration: '6 weeks',
      level: 'Intermediate',
      progress: 0
    },
    {
      id: 3,
      title: 'Local Wildlife Protection',
      description: 'Discover and protect the wildlife in your local environment.',
      image: '/local.jpg',
      duration: '5 weeks',
      level: 'Beginner',
      progress: 0
    },
    {
      id: 4,
      title: 'Sustainable Practices',
      description: 'Learn sustainable practices for wildlife and habitat protection.',
      image: '/sustainable.jpg',
      duration: '4 weeks',
      level: 'Intermediate',
      progress: 0
    },
    {
      id: 5,
      title: 'Ecological Impact',
      description: 'Understand ecological footprints and their effects on wildlife.',
      image: '/ecological.jpg',
      duration: '5 weeks',
      level: 'Advanced',
      progress: 0
    },
    {
      id: 6,
      title: 'Wildlife Photography',
      description: 'Master the art of wildlife photography and documentation.',
      image: '/wildlife-photography.jpg',
      duration: '6 weeks',
      level: 'Intermediate',
      progress: 0
    }
  ];

  const toggleMenu = () => {
    setMenuOpen(!menuOpen);
  };

  const handleMenuClick = (tab) => {
    setActiveTab(tab);
    setMenuOpen(false);
  };

  const getFilteredCourses = () => {
    if (activeTab === 'all') return courses;
    if (activeTab === 'beginner') return courses.filter(c => c.level === 'Beginner');
    if (activeTab === 'intermediate') return courses.filter(c => c.level === 'Intermediate');
    if (activeTab === 'advanced') return courses.filter(c => c.level === 'Advanced');
    return courses;
  };

  return (
    <div className="courses-page">
      <div className="courses-hero">
        <h1>Wildlife Education Courses</h1>
        <p>Expand your knowledge and contribute to wildlife conservation</p>
      </div>

      <div className="courses-container">
        <div className={`course-filters ${menuOpen ? 'open' : ''}`}>
          <div className="filter-toggle" onClick={toggleMenu}>
            <span>Filter Courses</span>
            <div className="hamburger">
              <div></div>
              <div></div>
              <div></div>
            </div>
          </div>
          <ul className="filter-options">
            <li 
              className={activeTab === 'all' ? 'active' : ''}
              onClick={() => handleMenuClick('all')}
            >
              All Courses
            </li>
            <li 
              className={activeTab === 'beginner' ? 'active' : ''}
              onClick={() => handleMenuClick('beginner')}
            >
              Beginner
            </li>
            <li 
              className={activeTab === 'intermediate' ? 'active' : ''}
              onClick={() => handleMenuClick('intermediate')}
            >
              Intermediate
            </li>
            <li 
              className={activeTab === 'advanced' ? 'active' : ''}
              onClick={() => handleMenuClick('advanced')}
            >
              Advanced
            </li>
          </ul>
        </div>

        <div className="courses-grid">
          {getFilteredCourses().map(course => (
            <div key={course.id} className="course-card">
              <div className="course-image-container">
                <img src={course.image} alt={course.title} className="course-image" />
                <span className="course-level">{course.level}</span>
              </div>
              <div className="course-content">
                <h2>{course.title}</h2>
                <p className="course-description">{course.description}</p>
                <div className="course-meta">
                  <span className="duration">{course.duration}</span>
                  {course.progress > 0 && (
                    <div className="progress-bar">
                      <div 
                        className="progress-fill" 
                        style={{ width: `${course.progress}%` }}
                      ></div>
                    </div>
                  )}
                </div>
                <Link to={`/course/${course.id}`} className="enroll-button">
                  Enroll Now
                </Link>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default Courses;
